---聚焦效果
---
---@class LBattleSkillActShowFocus
local LBattleSkillActShowFocus = classX("LBattleSkillActShowFocus", nil)

---@param player LBattleSkillPlayer
---@param effData LSkillEffectData
---@param playState LBattleSkillPlayState
function LBattleSkillActShowFocus.Execute(player,effData, playState)
    local recordHurtId = {}

    local atkUnitView = player:GetAtkUnitView()
    local atkUnitViewId = atkUnitView and atkUnitView:GetId()
    
    local _viewMgr = player:GetViewMgr()
    local effectCtrl = _viewMgr:GetEffectCtrl()

    local actionHurtDataList = player:GetSkillHurtDataList() or {}
    for k, v in ipairs(actionHurtDataList) do
        for k1,v1 in ipairs(v) do
            if v1.beforeList and #v1.beforeList > 0 then
                for idx,val in ipairs(v1.beforeList) do
                    if val.ht and val.ht == LFightConst.HURT_TYPE_DIVIDE_EQUALLY then
                        local id = v1.hitHurt.eId
                        ---@type LBattleViewUnit
                        local tarObj = _viewMgr:GetUnitView(id)
                        if tarObj then
                            recordHurtId[id] = true
                        end
                    end
                end
            end
            if v1.hitHurt then
                local id = v1.hitHurt.eId
                ---@type LBattleViewUnit
                local tarObj = _viewMgr:GetUnitView(id)
                if tarObj then
                    recordHurtId[id] = true
                end
            end
        end
    end

    --- 溅射目标
    local spurtingHitHeros = player:GetSpurtingHitHeros() or {}
    for i,v1 in ipairs(spurtingHitHeros) do
        if v1.hitHurt then
            local id = v1.hitHurt.eId
            ---@type LBattleViewUnit
            local tarObj = _viewMgr:GetUnitView(id)
            if tarObj then
                recordHurtId[id] = true
            end
        end
    end

    effectCtrl:HidePlayingEffects(recordHurtId,atkUnitViewId)

    local recordDownMaskMap = {}
    local viewMgr = _viewMgr
    if viewMgr then
        local battleObjList = viewMgr:GetUnitMgr():GetUnitMap() or {}
        local id
        for i,v in pairs(battleObjList) do
            id = v:GetId()
            if id ~= atkUnitViewId and not v:IsDead() then
                if not recordHurtId[id] then
                    recordDownMaskMap[id] = {
                        obj = v,
                    }
                    v:SetBattleObjState(0)
                    v:ShowBuffEffect(false)
                end
            end
        end
    end



    local fade = player:GetFadeObj()
    local para =
    {
        parentRoot =_viewMgr:GetFadeRoot(),
        startTime = _viewMgr:GetTime(),
        playTime = effData.playTime, --光效持续时间
        dissipateTime = effData.dissipateTime, --光效消散时间
        alpha = tonumber(effData.playNum),
        layer = "Object",
        order = 1,
        type = LBattleFadeType.TYPE_FOUR,
        callback = function()
            for k,v in pairs(recordDownMaskMap) do
                v.obj:SetBattleObjState(1)
                v.obj:ShowBuffEffect_1(true)
            end
            effectCtrl:ShowPlayingEffects()
        end
    }

    fade:Initialize(para)
end

return LBattleSkillActShowFocus